// PRODUCTION: Replace mock data with Jira REST API call:
// GET https://your-domain.atlassian.net/rest/api/3/search
// ?jql=project=PROJ&fields=summary,description,status,assignee
// Auth: Basic base64(email:api_token)

const mockTickets = [
  { ticket_id: 'PROJ-101', title: 'Optimize OAuth handshake latency', description: 'Users on mobile devices experience a 2-3 second delay during the OAuth login flow. Investigation points to redundant token validation calls. Need to cache the initial handshake response and reduce round trips to the auth service.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-101' },
  { ticket_id: 'PROJ-102', title: 'Fix payment gateway timeout on checkout', description: 'Stripe webhook occasionally times out after 30 seconds during high traffic. Implement async processing with a queue to handle retries gracefully.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-102' },
  { ticket_id: 'PROJ-103', title: 'Dashboard charts not rendering on Safari', description: 'Chart.js graphs fail to render on Safari 16 and below due to a missing polyfill for ResizeObserver. Affects approximately 12% of our user base.', status: 'In Progress', url: 'https://demo.atlassian.net/browse/PROJ-103' },
  { ticket_id: 'PROJ-104', title: 'Add dark mode support to settings page', description: 'Implement CSS variables and a theme toggle in user preferences. Should persist selection to localStorage and respect system preference on first visit.', status: 'To Do', url: 'https://demo.atlassian.net/browse/PROJ-104' },
  { ticket_id: 'PROJ-105', title: 'Email notifications not sending for new signups', description: 'SendGrid integration stopped delivering welcome emails after the SMTP config migration. Logs show 421 connection refused errors.', status: 'Done', url: 'https://demo.atlassian.net/browse/PROJ-105' }
];

return mockTickets.map(t => ({ json: t }));

const item = $input.first().json;

// Edge case: handle empty or missing description
const title = item.title?.trim() || 'Untitled';
const description = item.description?.trim();

// If no description: embed title only, flag for monitoring
const embedText = description && description.length > 5
  ? `${title}. ${description}`
  : title;

const hasDescription = !!(description && description.length > 5);

return [{ json: { ...item, embed_text: embedText, has_description: hasDescription } }];
